#![allow(clippy::unwrap_used, clippy::expect_used, clippy::doc_markdown)]

use mqo_eval::oracle::pgwire_password;

#[test]
fn acceptance_ac6() {
    // When ATSCALE_PG_PASS is not set, pgwire_password must return Err (not panic).
    std::env::remove_var("ATSCALE_PG_PASS");
    let result = pgwire_password("ATSCALE_PG_PASS");
    assert!(
        result.is_err(),
        "absent ATSCALE_PG_PASS must yield Err, not panic"
    );
    let err_msg = format!("{:#}", result.unwrap_err());
    assert!(
        err_msg.contains("ATSCALE_PG_PASS"),
        "error message must name the missing env var; got: {err_msg}"
    );

    // If ATSCALE_PG_PASS is set, pgwire_password returns Ok with the value.
    std::env::set_var("ATSCALE_PG_PASS", "test_password");
    let result = pgwire_password("ATSCALE_PG_PASS");
    assert!(result.is_ok(), "present env var must return Ok");
    assert_eq!(result.unwrap(), "test_password");
    std::env::remove_var("ATSCALE_PG_PASS");
}
